import { Router } from 'express';
import { furnitureController } from '../controllers/furnitureController.js';
import { propertyController } from '../controllers/propertyController.js';
import { tipController } from '../controllers/tipController.js';
export const apiRouter = Router();
apiRouter.get('/health', (_request, response) => response.json({ status: 'ok' }));
apiRouter.get('/properties', propertyController.list.bind(propertyController));
apiRouter.post('/properties/bulk', propertyController.createMany.bind(propertyController));
apiRouter.patch('/properties/:id/review', propertyController.updateReview.bind(propertyController));
apiRouter.delete('/properties/:id', propertyController.delete.bind(propertyController));
apiRouter.get('/furniture/categories', furnitureController.listCategories.bind(furnitureController));
apiRouter.post('/furniture/categories', furnitureController.createCategory.bind(furnitureController));
apiRouter.get('/furniture/items', furnitureController.listItems.bind(furnitureController));
apiRouter.post('/furniture/items', furnitureController.createItem.bind(furnitureController));
apiRouter.delete('/furniture/items/:id', furnitureController.deleteItem.bind(furnitureController));
apiRouter.get('/tips', tipController.list.bind(tipController));
